import React from 'react'
import  {motion , useMotionValue, useTransform , useSpring} from 'framer-motion';

function Interactive_bg() {

  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  // Create smoothed motion (spring)
  const smoothX = useSpring(mouseX, { stiffness: 50, damping: 50 });
  const smoothY = useSpring(mouseY, { stiffness: 50, damping: 50 });

  // Slight parallax translation
  const translateX = useTransform(smoothX, [0, window.innerWidth], [-50, 50]);
  const translateY = useTransform(smoothY, [0, window.innerHeight], [-50, 50]);

  // Mouse move handler
  const handleMouseMove = (e) => {
    mouseX.set(e.clientX);
    mouseY.set(e.clientY);
  };
  return (
    <div
    onMouseMove={handleMouseMove} className='absolute inset-0 overflow-hidden'>
         <motion.div
        style={{ x: translateX, y: translateY }}
        className="absolute w-[600px] h-[600px] rounded-full bg-gradient-to-r from-blue-500 to-pink-500 opacity-30 blur-3xl top-[-10%] left-[-10%]"
      />
      <motion.div
        style={{ x: translateX, y: translateY }}
        className="absolute w-[500px] h-[500px] rounded-full bg-gradient-to-r from-purple-500 to-cyan-400 opacity-30 blur-3xl bottom-[-10%] right-[-10%]"
      />
    </div>
  )
}

export default Interactive_bg

import { createContext, useContext, useState, useEffect } from "react";
import { loginUser as apiLoginUser, logoutUser as apiLogoutUser, registerUser as apiRegisterUser, loginGuest as apiLoginGuest } from '../api/userApi';
import { useNavigate } from "react-router-dom";

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(false);
  }, []);

  // LOGIN
  const loginUser = async (credentials) => {
    try {
      const { data } = await apiLoginUser(credentials);
      setUser(data.data);
      navigate("/rooms"); // redirect after login
    } catch (error) {
      throw error;
    }
  };

  // LOGIN AS GUEST
  const loginAsGuest = async () => {
    try {
      setLoading(true);
      const { data } = await apiLoginGuest();
      setUser(data.data);
      navigate("/rooms"); // redirect to Dashboard/Lobby
    } catch (error) {
      throw error;
    } finally {
      setLoading(false);
    }
  };

  // LOGOUT
  const logout = async () => {
    try {
      await apiLogoutUser();
      setUser(null);
      navigate("/login");
    } catch (error) {
      throw error;
    }
  };

  // REGISTER
  const register = async (credentials) => {
    try {
      const { data } = await apiRegisterUser(credentials);
      setUser(data.data);
      navigate("/rooms");
    } catch (error) {
      throw error;
    }
  };

  return (
    <AuthContext.Provider
      value={{ user, loading, loginUser, logout, register, loginAsGuest }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

import { createContext , useContext , useState , useEffect, Children  } from "react";
import { getMessage , deleteMessage  , sendMessage } from "../api/messageApi";
import { useSocket } from "./SocketContext";
import {useAuth} from './AuthContext';
const MessageContext  = createContext();
export const  MessageProvider = ({children})=>{
    const  [messages , setMessages]= useState([]);
    const [loading , setLoading]= useState(false);
    const {user}= useAuth();
const {socket}= useSocket();
    const fetchMessages =async(roomCode)=>{
   try {
    setLoading(true);
    const {data}= await getMessage(roomCode);
    setMessages(data.messages||[]);
   } catch (error) {
    console.error("Error fetching Message",error);
   } finally{
    setLoading(false);
   }
    }

    const handleDeleteMessage=(messageId)=>{
        try {
            const {res}= deleteMessage(messageId);
            setMessages((prev)=>prev.filter(m=>m._id!=messageId))
            socket.emit('deleteMessage' , messageId);
        } catch (error) {
            console.error("Error deleting message:" ,error)
        }
    };
 
    const handleSendMessage = async( roomCode , content  , mediaUrl=null)=>{
        try {
            const messageData ={
                roomCode ,
                content ,
                mediaUrl,
            };
            const data = await sendMessage(messageData);
            setMessages((prev)=>[...prev , data.message]);
            socket.emit("sendMessage" , data.message)
        } catch (error) {
            console.log("Error sending message" , error)
        }
    };

     // Real-time socket updates
  useEffect(() => {
    if (!socket) return;

    socket.on("messageReceived", (newMessage) => {
      setMessages((prev) => [...prev, newMessage]);
    });

    socket.on("messageDeleted", (deletedId) => {
      setMessages((prev) => prev.filter((msg) => msg._id !== deletedId));
    });

    return () => {
      socket.off("messageReceived");
      socket.off("messageDeleted");
    };
  }, [socket]);

  return (
    <MessageContext.Provider
      value={{
        messages,
        loading,
        fetchMessages,
        handleSendMessage,
        handleDeleteMessage,
      }}
    >
      {children}
    </MessageContext.Provider>
  );
};

export const useMessages = () => useContext(MessageContext);

import { useContext, createContext, useEffect, useState } from "react";
import {
  deleteRoom,
  getRooms,
  createRoom,
  joinRoom,
  removeMember,
} from "../api/roomApi";
import { useAuth } from "./AuthContext";

const RoomContext = createContext();

export const RoomProvider = ({ children }) => {
  const { user } = useAuth();

  const [rooms, setRooms] = useState([]);
  const [selectedRoom, setSelectedRoom] = useState(null);
  const [loading, setLoading] = useState(false); // ✅ missing in your code

  // Fetch rooms when user logs in
  useEffect(() => {
    if (user) fetchRooms();
  }, [user]);

  // ✅ fetch rooms
  const fetchRooms = async () => {
    try {
      setLoading(true);
      const { data } = await getRooms();
      setRooms(data?.room || []);
    } catch (error) {
      console.error("Error fetching rooms:", error);
    } finally {
      setLoading(false);
    }
  };

  // ✅ create room
  const handleCreateRooms = async () => {
    try {
      const { data } = await createRoom();
      setRooms((prev) => [...prev, data.data]);
      return data.data;
    } catch (error) {
      console.error("Error creating room:", error);
      throw error;
    }
  };

  // ✅ join room
  const handleJoinRooms = async (code) => {
    try {
      const { data } = await joinRoom(code);
      setRooms((prev) => {
        const exists = prev.find((r) => r._id === data.data._id);
        return exists ? prev : [...prev, data.data];
      });
    } catch (error) {
      console.error("Error joining room:", error);
      throw error;
    }
  };

  // ✅ delete room
  const handleDeleteRoom = async (roomCode) => {
    try {
      await deleteRoom(roomCode);
      setRooms((prev) => prev.filter((r) => r.code !== roomCode));
      if (selectedRoom?.code === roomCode) setSelectedRoom(null);
    } catch (error) {
      console.error("Error deleting room:", error);
      throw error;
    }
  };

  // ✅ remove member
  const handleRemoveMember = async (roomCode, memberId) => {
    try {
      const { data } = await removeMember(roomCode, memberId);
      setRooms((prev) =>
        prev.map((r) => (r.code === roomCode ? data.data : r))
      );
    } catch (error) {
      console.error("Error removing member:", error);
      throw error;
    }
  };

  // ✅ context value
  return (
    <RoomContext.Provider
      value={{
        rooms,
        selectedRoom,
        setSelectedRoom,
        loading,
        fetchRooms,
        handleCreateRooms,
        handleJoinRooms,
        handleDeleteRoom,
        handleRemoveMember,
      }}
    >
      {children}
    </RoomContext.Provider>
  );
};

// ✅ correct hook name
export const useRoom = () => useContext(RoomContext);

import { createContext , useContext , useState , useEffect } from "react";
import io from "socket.io-client";
import { useAuth } from "./AuthContext";

 const SocketContext = createContext();
 export const SocketProvider =({children})=>{
    const {user}=  useAuth();
    const [socket , setSocket]= useState(null);
      useEffect(()=>{
        if(!user) return;

        const newSocket = io(import.meta.env.VITE_BAKCEND_URL , {
            withCredentials:true,
            query:{userId:user._id}
        });

        setSocket(newSocket);
        newSocket.on("connect",()=>{
            console.log("socket connected:" , newSocket.id);
        });

        newSocket.on("disconnected" , ()=>{
            console.log("socket disconnected");
        });

//clean up function

        return()=>{
            newSocket.disconnect();
        }
      },[user]);

      return (
        <SocketContext.Provider value={{socket}}>
            {children}
        </SocketContext.Provider>
      )
 };
 export const useSocket =()=> useContext(SocketContext);

import { useParams, useNavigate } from "react-router-dom";
import { useEffect, useRef, useState } from "react";
import { useMessages } from "../context/MessagContext";
import { useRoom } from "../context/RoomContext";
import { useAuth } from "../context/AuthContext";
import { useSocket } from "../context/SocketContext";
import MessageBubble from "../component/Chat/MessageBubble";
import MessageInput from "../component/Chat/MessageInput";

const ChatRoom = () => {
  const { roomCode } = useParams();
  const { messages, fetchMessages } = useMessages();
  const { rooms } = useRoom();
  const { user } = useAuth();
  const socket = useSocket();
  const navigate = useNavigate();

  const bottomRef = useRef();
  
  // States for Live Typewriter Effect
  const [liveTypingStr, setLiveTypingStr] = useState("");
  const [typingUser, setTypingUser] = useState("");
  const typingTimeoutRef = useRef(null);

  // If rooms isn't loaded yet, it might be undefined.
  const room = rooms?.find((r) => r.code === roomCode);

  useEffect(() => {
    fetchMessages(roomCode);
    
    // Typewriter Socket Listener
    if (socket) {
      socket.on("userTyping", (data) => {
        setTypingUser(data.username);
        setLiveTypingStr((prev) => prev + data.key);
        
        // Clear the live text if they stop typing for 2 seconds
        if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
        typingTimeoutRef.current = setTimeout(() => {
          setLiveTypingStr("");
          setTypingUser("");
        }, 2000);
      });
    }

    return () => {
      if (socket) socket.off("userTyping");
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    }
  }, [roomCode, socket]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  if (!room) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4">
        <div className="terminal-box text-center">
          <p className="text-[var(--accent-color)] glitch-anim uppercase mb-4">
            ERROR: ROOM_NOT_FOUND_OR_ACCESS_DENIED
          </p>
          <button className="btn-terminal" onClick={() => navigate('/rooms')}>
            [ ABORT_AND_RETURN ]
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col p-2 md:p-4 max-w-5xl mx-auto w-full">

      {/* HEADER */}
      <div className="border border-[var(--border-color)] p-4 mb-4 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-[var(--bg-color)]">
        <div>
          <h2 className="text-xl font-bold tracking-widest uppercase">
            {'>'} ROOM_HASH: <span className="text-[var(--accent-color)]">{room.code}</span>
          </h2>
          <p className="text-xs opacity-70 mt-1 uppercase">
            // ACTIVE_PARTICIPANTS: {room.members.length} | ENCRYPTION: ACTIVE
          </p>
        </div>

        <button
          className="btn-terminal text-xs text-[var(--accent-color)] border-[var(--accent-color)] hover:bg-[var(--accent-color)]"
          onClick={() => navigate('/rooms')}
        >
          [ DISCONNECT ]
        </button>
      </div>

      {/* CHAT CONTAINER */}
      <div className="flex-1 overflow-y-auto border border-[var(--border-color)] p-4 mb-4 flex flex-col gap-2 bg-[var(--bg-color)]">
        
        <div className="text-center opacity-30 text-xs mb-4 border-b border-dashed border-[var(--border-color)] pb-2 uppercase">
          --- CONNECTION_ESTABLISHED ---
        </div>

        {messages.map((msg, index) => (
          <MessageBubble key={msg._id || index} msg={msg} isOwn={msg.user_id?._id === user?._id} />
        ))}

        {/* Live Typewriter Effect */}
        {liveTypingStr && (
          <div className="flex flex-col w-full mb-4 items-start">
            <div className="text-xs opacity-50 mb-1 uppercase tracking-wider text-[var(--accent-color)] glitch-anim">
               {`> ${typingUser} IS_TYPING...`}
            </div>
            <div className="px-4 py-2 max-w-[85%] md:max-w-[70%] break-words border border-[var(--border-color)] bg-[var(--bg-color)] text-[var(--accent-color)] font-bold">
              {liveTypingStr}_
            </div>
          </div>
        )}

        <div ref={bottomRef}></div>
      </div>

      {/* INPUT BOX */}
      <MessageInput roomCode={roomCode} />
      
      <div className="text-center mt-2 opacity-30 text-[10px] uppercase">
        // DO NOT SHARE SENSITIVE INFORMATION. THIS ROOM CAN SELF DESTRUCT.
      </div>
    </div>
  );
};

export default ChatRoom;

import { Link } from "react-router-dom";
import Interactive_bg from "../component/Animation/Interactive_bg";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { useState } from "react";

const Landing = () => {
  const { loginAsGuest } = useAuth();
  const [isGlitching, setIsGlitching] = useState(false);
  const navigate = useNavigate();

  const handleGuestLogin = async () => {
    setIsGlitching(true);
    try {
      await loginAsGuest();
      // AuthContext handles navigation
    } catch (e) {
      console.error(e);
      setIsGlitching(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4">
      {/* Brutalist ASCII style header */}
      <div className={`text-center mb-16 ${isGlitching ? 'glitch-anim' : ''}`}>
        <h1 className="text-4xl md:text-6xl font-bold mb-4 tracking-tighter">
          [ GHOST_PROTOCOL ]
        </h1>
        <p className="text-sm md:text-base opacity-70">
          // SECURE. ANONYMOUS. EPHEMERAL.
        </p>
      </div>

      <div className="w-full max-w-md terminal-box flex flex-col gap-6">
        <div className="border-b border-[var(--border-color)] pb-4 mb-2">
          <p className="text-xs uppercase tracking-widest text-[var(--accent-color)]">
            {'>'} system_status: online
          </p>
        </div>

        <button 
          onClick={handleGuestLogin}
          className="btn-terminal w-full py-4 text-lg bg-[var(--text-color)] text-[var(--bg-color)] hover:bg-transparent hover:text-[var(--text-color)]"
        >
          {isGlitching ? "ESTABLISHING_CONNECTION..." : "ENTER_INCOGNITO (OMEGLE MODE)"}
        </button>

        <div className="flex items-center gap-4 text-xs opacity-50">
          <div className="h-px bg-[var(--border-color)] flex-grow"></div>
          <span>OR</span>
          <div className="h-px bg-[var(--border-color)] flex-grow"></div>
        </div>

        <div className="flex gap-4">
          <Link to="/login" className="btn-terminal flex-1 text-center">
            {'>'} LOGIN
          </Link>
          <Link to="/register" className="btn-terminal flex-1 text-center">
            {'>'} REGISTER
          </Link>
        </div>
      </div>

      <footer className="fixed bottom-4 text-xs opacity-30 text-center w-full">
        TRACE_LVL: 0% | ENCRYPTION: ACTIVE
      </footer>
    </div>
  );
};

export default Landing;

import { Link, useNavigate } from "react-router-dom";
import { useState } from "react";
import { useAuth } from "../context/AuthContext";

const LoginPage = () => {
  const [form, setForm] = useState({ username: "", password: "" });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const { loginUser } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) =>
    setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      await loginUser(form);
      // AuthContext handles navigation
    } catch (err) {
      const msg =
        err?.response?.data?.message ||
        err?.response?.data?.error ||
        "ERROR: ACCESS_DENIED. INVALID_CREDENTIALS.";
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4">
      <div className="w-full max-w-md terminal-box flex flex-col gap-6">
        
        <div className="border-b border-[var(--border-color)] pb-4 mb-2">
          <h1 className="text-xl font-bold uppercase">
           {'>'} USER_AUTHENTICATION
          </h1>
        </div>

        <p className="text-sm opacity-70">
          // ENTER_CREDENTIALS_TO_ACCESS_SYSTEM
        </p>

        {error && (
          <div className="border border-[var(--accent-color)] text-[var(--accent-color)] p-2 text-xs font-bold uppercase glitch-anim">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="flex flex-col gap-6">
          <div className="flex flex-col gap-2">
            <label className="text-xs opacity-70">USERNAME:</label>
            <input
              type="text"
              name="username"
              placeholder="e.g. Neo"
              className="input-terminal"
              value={form.username}
              onChange={handleChange}
              required
            />
          </div>

          <div className="flex flex-col gap-2">
            <label className="text-xs opacity-70">PASSWORD:</label>
            <input
              type="password"
              name="password"
              placeholder="••••••••"
              className="input-terminal"
              value={form.password}
              onChange={handleChange}
              required
            />
          </div>

          <button
            type="submit"
            className={`btn-terminal w-full py-4 text-lg mt-2 ${loading ? "opacity-50 cursor-not-allowed" : "bg-[var(--text-color)] text-[var(--bg-color)] hover:bg-transparent hover:text-[var(--text-color)]"}`}
            disabled={loading}
          >
            {loading ? "VERIFYING..." : "ENTER"}
          </button>
        </form>

        <div className="text-center mt-4">
          <Link to="/signup" className="text-xs hover:text-[var(--accent-color)] underline underline-offset-4">
            [ NO_ACCOUNT? _REGISTER_HERE ]
          </Link>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
